  ('heelevel3-988e0de1-moex-00119', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列何者最能描述規劃階段所執行分析性程序之目的？', '["決定委任合約應執行之事項", "辨識異常狀況以投入更多查核", "決定客戶之財務報表何項聲明最重要", "決定查核時間、性質與範圍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00120', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '會計師於了解甲公司之內部控制時，發現其職能分工不適當，此情況顯示該公司下列內部控 制組成要素中何者可能存有顯著缺失？', '["控制環境", "風險評估流程", "控制作業", "控制之監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00121', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '審計準則公報第51號「查核規劃及執行之重大性」 ，對於查核人員執行重大性之應用，下 列敘述何者錯誤？', '["判斷重大性水準時，查核人員應先決定整體財務報表重大性，亦得進一步分配初步判斷重 大性水準至財務報表的各科目", "查核人員於執行查核過程中，如發現特定重大交易導致必須修正財務報表重大性時，除了 修訂該特定交易之重大性外，亦應考量修正財務報表整體重大性", "查核人員於決定執行重大性時，不能僅就當年度之財務報表要素進行評估，以往年度查核 所辨認不實表達之性質與範圍，也會影響當年度執行重大性之決定", "查核人員於總各科目不實表達後，發現不實表達超過財務報表整體重大性，係因某特定 科目估計不實表達遠超過該科目執行重大性所致，查核人員得修正財務報表整體重大性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00122', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '集團主辦會計師決定為集團財務報表組成個體（子公司）其他查核人員之工作承擔責任時， 下列敘述何者錯誤？', '["集團主辦會計師團隊必須參與組成個體查核人員之工作，工作深度需達到可對集團財務報 表表示意見之程度", "集團主辦會計師團隊必須為組成個體決定其查核重大性，且組成個體重大性應低於集團財 務報表整體重大性", "集團主辦會計師應取得組成個體查核會計師出具之聲明書及查核報告，並將該查核報告與 集團查核報告一併列報", "集團主辦會計師團隊應決定並評估組成個體查核人員之工作是否足夠、是否需複核組成個 體查核人員之工作底稿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00123', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', 'A會計師受託查核甲公司X1年度（X1年1月1日至12月31日）財務報表，於X2年3月 1日結束外勤工作，返回事務所。在撰寫查核報告期間，甲公司之客戶於X2年3月8日發生 倒閉，導致該應收帳款無法收回。A會計師因此重新評估甲公司X1年12月31日之應收帳 款備抵呆帳是否提列足額，並於X2年3月20日完成查核程序，3月25日完成查核報告草 稿，3月31日甲公司財務報表經董事會通過。查核報告日最可能為那一天？', '["X2年3月1日", "X2年3月2日", "X2年3月20日", "X2年3月31日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00124', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列那一項查核程式可能屬於控制測試？', '["核對應收帳款總帳與明細帳餘額的一致性", "函證應收帳餘額", "評估應收帳款備抵呆帳的合理性", "檢查應收帳款入帳與出貨時點的一致性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00125', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '有關工作底稿之敘述，下列何者錯誤？', '["工作底稿之保管年限，自查核報告日起算不短於5年", "非經客戶同意，皆不得將工作底稿內容洩露給任何第三者", "若事務所內部契約無約定，會計師之工作底稿所有權屬於會計師事務所所有", "工作底稿保管期限屆滿前，不得予以刪除或銷毀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00126', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '查核人員原預估控制風險水準是10%，經執行內部控制測試後評估控制風險水準為25%，則 查核人員最好應：', '["提高可接受查核風險水準", "降低可接受查核風險水準", "降低固有風險水準", "降低可接受偵查風險水準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00127', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '關於繼任會計師應向前任會計師查詢之規定，下列敘述何者錯誤？', '["查詢之事項通常會包括委任人管理當局之品德", "前任會計師非經委任人同意或正當理由，不得將查核過程中所獲得之資訊告知繼任會計師", "繼任會計師應主動與前任會計師連繫，且須以書面為之", "繼任會計師應考慮前任會計師回覆內容之涵義以決定是否接受委任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00128', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '查核人員針對應收帳款餘額發出函證，但未能取得回函，下列何者為較不可能執行之替代程序？', '["再次寄發詢證函", "查核接近期末之銷貨", "另行選樣替代未回函之受函證者", "查核期後收款"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL)
